import numpy as np

def f(x, y):
    return x**2 + 3 * x * y + y**2

def grad_f(x, y):
    df_dx = 2 * x + 3 * y
    df_dy = 3 * x + 2 * y
    return np.array([df_dx, df_dy])

x, y = 1.0, -1.0
g = grad_f(x, y)
print("grad:", g, "norm:", np.linalg.norm(g))

import numpy as np

def f_vec(x):
    return x[0]**2 + 3 * x[0] * x[1] + x[1]**2

def grad_analytic(x):
    return np.array([2 * x[0] + 3 * x[1], 3 * x[0] + 2 * x[1]])

def grad_numeric(f, x, h=1e-5):
    g = np.zeros_like(x, dtype=float)
    for i in range(len(x)):
        e = np.zeros_like(x, dtype=float)
        e[i] = h
        g[i] = (f(x + e) - f(x - e)) / (2 * h)
    return g

x = np.array([1.0, -1.0])
print(np.linalg.norm(grad_analytic(x) - grad_numeric(f_vec, x)))
